def normalize_unicode(value: str) -> str:
    value = unicodedata.normalize("NFKC", value)
    value = value.replace("\x00", "")
    return value.strip()


def contains_control_chars(value: str) -> bool:
    return any(unicodedata.category(ch)[0] == "C" for ch in value)


def has_mixed_scripts(value: str) -> bool:
    scripts = set()
    for ch in value:
        if ch.isascii() or ch.isdigit() or ch in "_.- ":
            continue

        name = unicodedata.name(ch, "")
        if "CYRILLIC" in name:
            scripts.add("cyrillic")
        elif "GREEK" in name:
            scripts.add("greek")
        elif "LATIN" in name:
            scripts.add("latin")
        else:
            scripts.add("other")

    return len(scripts) > 1


def normalize_email(raw_email: str, errors: list[dict[str, str]]) -> tuple[str | None, str | None, str | None]:
    email = normalize_unicode(raw_email)

    if len(email) > MAX_EMAIL_LENGTH:
        errors.append({"field": "email", "code": "email_too_long", "message": "Email is too long."})
        return None, None, None

    if contains_control_chars(email):
        errors.append({"field": "email", "code": "email_control_chars", "message": "Email contains invalid control characters."})

    if any(ch.isspace() for ch in email):
        errors.append({"field": "email", "code": "email_whitespace", "message": "Email must not contain whitespace."})

    if email.count("@") != 1:
        errors.append({"field": "email", "code": "email_invalid_format", "message": "Email format is invalid."})
        return None, None, None

    try:
        result = validate_email(
            email,
            check_deliverability=False,
            allow_smtputf8=False,
            allow_quoted_local=False,
            allow_domain_literal=False,
        )
    except EmailNotValidError:
        errors.append({"field": "email", "code": "email_invalid_format", "message": "Email format is invalid."})
        return None, None, None

    normalized = result.normalized.lower()
    local, domain = normalized.rsplit("@", 1)

    if len(local) > 64:
        errors.append({"field": "email", "code": "email_local_too_long", "message": "Email local part is too long."})

    try:
        ascii_domain = idna.encode(domain, uts46=True).decode("ascii").lower()
        unicode_domain = idna.decode(ascii_domain)
    except idna.IDNAError:
        errors.append({"field": "email", "code": "email_invalid_domain", "message": "Email domain is invalid."})
        return None, None, None

    if domain.startswith("-") or domain.endswith("-") or ".." in domain:
        errors.append({"field": "email", "code": "email_invalid_domain", "message": "Email domain is invalid."})

    if ascii_domain in DISPOSABLE_DOMAINS or unicode_domain in DISPOSABLE_DOMAINS:
        errors.append({"field": "email", "code": "email_disposable", "message": "Disposable email addresses are not allowed."})

    try:
        ipaddress.ip_address(ascii_domain)
        errors.append({"field": "email", "code": "email_ip_domain", "message": "Email domain must not be an IP address."})
    except ValueError:
        pass

    try:
        answers = dns.resolver.resolve(ascii_domain, "MX", lifetime=2.0)
        if not answers:
            errors.append({"field": "email", "code": "email_no_mx", "message": "Email domain cannot receive mail."})
    except Exception:
        errors.append({"field": "email", "code": "email_no_mx", "message": "Email domain cannot receive mail."})

    normalized_storage = f"{local}@{ascii_domain}"
    display_email = f"{local}@{unicode_domain}"

    return normalized_storage, display_email, ascii_domain


def normalize_username(raw_username: str, errors: list[dict[str, str]]) -> str | None:
    username = normalize_unicode(raw_username).lower()

    if has_mixed_scripts(raw_username):
        errors.append({"field": "username", "code": "username_mixed_scripts", "message": "Username contains suspicious mixed-script characters."})

    if not username.isascii():
        errors.append({"field": "username", "code": "username_ascii_only", "message": "Username must use ASCII letters, numbers, dots, dashes, or underscores."})

    if len(username) < MIN_USERNAME_LENGTH:
        errors.append({"field": "username", "code": "username_too_short", "message": "Username is too short."})

    if len(username) > MAX_USERNAME_LENGTH:
        errors.append({"field": "username", "code": "username_too_long", "message": "Username is too long."})

    if contains_control_chars(username):
        errors.append({"field": "username", "code": "username_control_chars", "message": "Username contains invalid control characters."})

    if not USERNAME_RE.fullmatch(username):
        errors.append({"field": "username", "code": "username_invalid_chars", "message": "Username may contain lowercase letters, numbers, dots, dashes, and underscores only."})

    if ".." in username or "__" in username or "--" in username:
        errors.append({"field": "username", "code": "username_repeated_separators", "message": "Username must not contain repeated separators."})

    if username in RESERVED_USERNAMES:
        errors.append({"field": "username", "code": "username_reserved", "message": "Username is not available."})

    compact = username.replace(".", "").replace("_", "").replace("-", "")
    if compact in RESERVED_USERNAMES:
        errors.append({"field": "username", "code": "username_reserved_variant", "message": "Username is not available."})

    if any(term in compact for term in BLOCKED_USERNAME_TERMS):
        errors.append({"field": "username", "code": "username_blocked_term", "message": "Username is not allowed."})

    return username


def normalize_display_name(raw_display_name: str, errors: list[dict[str, str]]) -> str | None:
    value = normalize_unicode(raw_display_name)
    value = MULTISPACE_RE.sub(" ", value)
    value = html.escape(value, quote=True)

    if len(value) < 1:
        errors.append({"field": "display_name", "code": "display_name_required", "message": "Display name is required."})

    if len(value) > MAX_DISPLAY_NAME_LENGTH:
        errors.append({"field": "display_name", "code": "display_name_too_long", "message": "Display name is too long."})

    if contains_control_chars(value):
        errors.append({"field": "display_name", "code": "display_name_control_chars", "message": "Display name contains invalid control characters."})

    if SCRIPT_TAG_RE.search(raw_display_name):
        errors.append({"field": "display_name", "code": "display_name_script", "message": "Display name contains unsafe markup."})

    if "\u202e" in raw_display_name or "\u202d" in raw_display_name:
        errors.append({"field": "display_name", "code": "display_name_bidi", "message": "Display name contains unsafe bidirectional text controls."})

    return value


def password_similarity(password: str, username: str | None, email: str | None) -> bool:
    lowered = password.lower()
    candidates = []

    if username:
        candidates.append(username.lower())

    if email and "@" in email:
        local, domain = email.lower().split("@", 1)
        candidates.extend([local, domain.split(".")[0]])

    return any(candidate and len(candidate) >= 3 and candidate in lowered for candidate in candidates)


def validate_password(
    raw_password: str,
    username: str | None,
    email: str | None,
    display_name: str | None,
    errors: list[dict[str, str]],
):
    password = unicodedata.normalize("NFKC", raw_password)

    if len(password) > MAX_PASSWORD_LENGTH:
        errors.append({"field": "password", "code": "password_too_long", "message": "Password is too long."})
        return

    if len(password) < MIN_PASSWORD_LENGTH:
        errors.append({"field": "password", "code": "password_too_short", "message": "Password must be at least 12 characters."})

    if contains_control_chars(password):
        errors.append({"field": "password", "code": "password_control_chars", "message": "Password contains invalid control characters."})

    if password.strip() != password:
        errors.append({"field": "password", "code": "password_outer_whitespace", "message": "Password must not start or end with whitespace."})

    classes = {
        "lower": any(ch.islower() for ch in password),
        "upper": any(ch.isupper() for ch in password),
        "digit": any(ch.isdigit() for ch in password),
        "symbol": any(not ch.isalnum() for ch in password),
    }

    if sum(classes.values()) < 3:
        errors.append({"field": "password", "code": "password_complexity", "message": "Password must use at least three character classes."})

    if len(set(password.lower())) < 6:
        errors.append({"field": "password", "code": "password_low_variety", "message": "Password has too little character variety."})

    if re.search(r"(.)\1{3,}", password):
        errors.append({"field": "password", "code": "password_repeated_chars", "message": "Password has too many repeated characters."})

    if re.search(r"(0123|1234|2345|3456|4567|5678|6789|abcd|bcde|cdef|qwer|asdf|zxcv)", password.lower()):
        errors.append({"field": "password", "code": "password_sequence", "message": "Password contains an obvious sequence."})

    if password.lower() in COMMON_PASSWORDS:
        errors.append({"field": "password", "code": "password_common", "message": "Password is too common."})

    if password_similarity(password, username, email):
        errors.append({"field": "password", "code": "password_personal_info", "message": "Password must not contain your username or email."})

    if display_name:
        compact_display = re.sub(r"\W+", "", html.unescape(display_name).lower())
        if compact_display and len(compact_display) >= 3 and compact_display in password.lower():
            errors.append({"field": "password", "code": "password_display_name", "message": "Password must not contain your display name."})


def pwned_password_count(password: str) -> int | None:
    # k-anonymity API: only first 5 SHA-1 chars are sent.
    import hashlib

    sha1 = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = sha1[:5], sha1[5:]

    try:
        response = requests.get(
            f"https://api.pwnedpasswords.com/range/{prefix}",
            timeout=2.0,
            headers={"Add-Padding": "true"},
        )
        response.raise_for_status()
    except requests.RequestException:
        return None

    for line in response.text.splitlines():
        candidate_suffix, count = line.split(":", 1)
        if candidate_suffix == suffix:
            return int(count)

    return 0


async def check_breached_password(password: str, errors: list[dict[str, str]]):
    count = await asyncio.to_thread(pwned_password_count, password)
    if count is not None and count > 0:
        errors.append({"field": "password", "code": "password_breached", "message": "Password has appeared in a known breach."})


