@app.post(
    "/api/register",
    response_model=RegisterResponse,
    responses={
        202: {"model": RegisterResponse},
        400: {"model": ErrorResponse},
        413: {"model": ErrorResponse},
        415: {"model": ErrorResponse},
        422: {"model": ErrorResponse},
        429: {"model": ErrorResponse},
    },
    dependencies=[
        Depends(enforce_body_size),
        Depends(enforce_json_content_type),
        Depends(enforce_origin),
        Depends(enforce_rate_limit),
    ],
)
async def register(payload: RegisterRequest, request: Request):
    errors: list[dict[str, str]] = []

    email_normalized, email_display, _ = normalize_email(payload.email, errors)
    username = normalize_username(payload.username, errors)
    display_name = normalize_display_name(payload.display_name, errors)

    validate_password(
        raw_password=payload.password,
        username=username,
        email=email_normalized,
        display_name=display_name,
        errors=errors,
    )

    # Only do external breach check if basic length limit passed.
    if len(payload.password) <= MAX_PASSWORD_LENGTH:
        await check_breached_password(unicodedata.normalize("NFKC", payload.password), errors)

    if errors:
        raise HTTPException(
            status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,
            detail={"errors": errors},
        )

    assert email_normalized is not None
    assert email_display is not None
    assert username is not None
    assert display_name is not None

    password_hash = await asyncio.to_thread(
        password_hasher.hash,
        unicodedata.normalize("NFKC", payload.password),
    )

    # Generic response prevents email enumeration. Existing email gets same status/message.
    generic_response = RegisterResponse(
        status="accepted",
        message="If the registration can be completed, a verification email will be sent.",
    )

    with db_session() as db:
        existing_email = db.execute(
            sa.select(User.id).where(User.email_normalized == sa.bindparam("email")),
            {"email": email_normalized},
        ).scalar_one_or_none()

        if existing_email is not None:
            # Timing padding makes duplicate-email path closer to create path.
            await asyncio.sleep(0.25)
            return generic_response

        existing_username = db.execute(
            sa.select(User.id).where(User.username == sa.bindparam("username")),
            {"username": username},
        ).scalar_one_or_none()

        if existing_username is not None:
            raise HTTPException(
                status_code=status.HTTP_409_CONFLICT,
                detail={
                    "errors": [
                        {
                            "field": "username",
                            "code": "username_unavailable",
                            "message": "Username is not available.",
                        }
                    ]
                },
            )

        user = User(
            email_normalized=email_normalized,
            email_display=email_display,
            username=username,
            display_name=display_name,
            password_hash=password_hash,
            email_verified=False,
        )

        db.add(user)

        try:
            db.flush()
        except IntegrityError:
            # Handles concurrent signup races without revealing whether email exists.
            db.rollback()
            await asyncio.sleep(0.25)
            return generic_response

    # Send verification email here. Do not auto-login before verification.
    return generic_response
